INSERT INTO `mails` VALUES (41,'noreply@tufratech.com','ahmedtriki.triki5@gmail.com',NULL,NULL,'Bienvenue chez Visioncraft !','<!doctype html>\r\n<html lang=\"fr\">\r\n<head>\r\n  <meta charset=\"utf-8\" />\r\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\" />\r\n  <title>Bienvenue ?????? Auravue</title>\r\n\r\n  <style>\r\n    /* Reset minimal (garde important pour emails/pages) */\r\n    html,body{margin:0;padding:0;height:100%}\r\n    img{border:0;display:block;max-width:100%}\r\n    a{text-decoration:none}\r\n\r\n    /* Container */\r\n    .page {\r\n      min-height:100vh;\r\n      display:flex;\r\n      align-items:center;\r\n      justify-content:center;\r\n      background: linear-gradient(180deg,#f7f8fa 0%, #f2f4f7 100%);\r\n      font-family: system-ui, -apple-system, \"Segoe UI\", Roboto, \"Helvetica Neue\", Arial;\r\n      padding:32px;\r\n      box-sizing:border-box;\r\n    }\r\n\r\n    /* Card */\r\n    .card {\r\n      width:100%;\r\n      max-width:540px;\r\n      background:#ffffff;\r\n      border-radius:18px;\r\n      box-shadow: 0 10px 30px rgba(16,24,40,0.08);\r\n      padding:44px 40px;\r\n      box-sizing:border-box;\r\n      text-align:center;\r\n      transition: transform .22s ease, box-shadow .22s ease;\r\n    }\r\n    .card:hover{\r\n      transform: translateY(-6px);\r\n      box-shadow: 0 20px 40px rgba(16,24,40,0.12);\r\n    }\r\n\r\n    /* Top icon/logo */\r\n    .logo-wrap{\r\n      width:88px;\r\n      height:88px;\r\n      margin:0 auto 18px;\r\n      display:flex;\r\n      align-items:center;\r\n      justify-content:center;\r\n      border-radius:16px;\r\n      background: linear-gradient(180deg,#0f172a 0%, #0b1220 100%);\r\n      color:#fff;\r\n      font-weight:700;\r\n      box-shadow: inset 0 -6px 18px rgba(255,255,255,0.02);\r\n    }\r\n\r\n    h1 {\r\n      margin:6px 0 12px;\r\n      font-size:22px;\r\n      color:#0f172a;\r\n      line-height:1.15;\r\n      letter-spacing:-0.2px;\r\n    }\r\n\r\n    p.lead {\r\n      margin:0 0 22px;\r\n      color:#4b5563;\r\n      font-size:15px;\r\n      line-height:1.6;\r\n    }\r\n\r\n    /* Button */\r\n    .btn {\r\n      display:inline-block;\r\n      padding:12px 26px;\r\n      border-radius:10px;\r\n      background:linear-gradient(90deg,#2563eb,#0ea5e9);\r\n      color:#fff;\r\n      font-weight:600;\r\n      font-size:15px;\r\n      box-shadow: 0 6px 18px rgba(14,165,233,0.18);\r\n      transition: transform .12s ease, box-shadow .12s ease, opacity .12s;\r\n      margin:0 auto;\r\n    }\r\n    .btn:hover{ transform: translateY(-3px); box-shadow: 0 12px 30px rgba(14,165,233,0.20); }\r\n    .btn:active{ transform: translateY(0); opacity:0.95; }\r\n\r\n    /* Small helper text & info box */\r\n    .muted {\r\n      margin-top:26px;\r\n      color:#6b7280;\r\n      font-size:13px;\r\n      line-height:1.6;\r\n    }\r\n\r\n    .info {\r\n      margin-top:26px;\r\n      padding:18px;\r\n      background:#f8fafc;\r\n      border-radius:10px;\r\n      border:1px solid rgba(15,23,42,0.03);\r\n      color:#6b7280;\r\n      font-size:13px;\r\n      line-height:1.5;\r\n    }\r\n\r\n    /* Footer */\r\n    .footer {\r\n      margin-top:18px;\r\n      font-size:12px;\r\n      color:#9ca3af;\r\n    }\r\n\r\n    /* Responsive */\r\n    @media (max-width:520px){\r\n      .card { padding:28px 20px; border-radius:14px; }\r\n      h1 { font-size:20px; }\r\n      .logo-wrap { width:72px; height:72px; border-radius:12px; margin-bottom:12px; }\r\n      .btn { width:100%; box-sizing:border-box; padding:12px; }\r\n    }\r\n  </style>\r\n</head>\r\n\r\n<body>\r\n  <div class=\"page\">\r\n    <div class=\"card\" role=\"article\" aria-labelledby=\"title\">\r\n      <!-- Logo / Icon -->\r\n      <div class=\"logo-wrap\" aria-hidden=\"true\">\r\n        \r\n        <span style=\"font-size:34px; line-height:1;\">????????</span>\r\n      </div>\r\n\r\n      <!-- Title -->\r\n      <h1 id=\"title\">Bienvenue, v?????rifiez votre email</h1>\r\n\r\n      <!-- Lead text -->\r\n      <p class=\"lead\">\r\n        Bonjour <strong>ahmedtriki.triki5</strong>, merci de vous ?????tre inscrit sur\r\n        <strong>Auravue</strong>. Cliquez sur le bouton ci-dessous pour activer votre compte.\r\n      </p>\r\n\r\n      <!-- CTA button -->\r\n      <p>\r\n        <a class=\"btn\"\r\n           href=\"#\"\r\n           role=\"button\"\r\n           title=\"V?????rifier mon compte\">\r\n           V?????rifier mon compte\r\n        </a>\r\n      </p>\r\n\r\n      <!-- Secondary -->\r\n      <div class=\"muted\">\r\n        Si le bouton ne fonctionne pas, copie/colle ce lien dans ton navigateur :\r\n        <br>\r\n        <a href=\"#\" style=\"color:#2563eb; word-break:break-all;\">\r\n          (lien non fourni)\r\n        </a>\r\n      </div>\r\n\r\n      <div class=\"info\" aria-hidden=\"false\">\r\n        <strong>Pourquoi ce mail ?</strong>\r\n        <div>Nous envoyons cet e-mail pour confirmer que l??????adresse que vous avez fournie vous appartient et s?????curiser votre compte.</div>\r\n      </div>\r\n\r\n      <div class=\"footer\">\r\n        Cordialement ?????? l\'?????quipe Auravue\r\n      </div>\r\n    </div>\r\n  </div>\r\n</body>\r\n</html>\r\n',NULL,'newsletter',1,'SENT','2025-12-04 12:15:03',NULL,NULL,'2025-12-04 11:58:46','2025-12-04 12:15:03'),(42,'noreply@tufratech.com','ahmedtriki.triki5@gmail.com',NULL,'[\"ahmed_triki@icloud.com\"]','testdeali','testdeali',NULL,'admin',1,'SENT','2025-12-04 12:31:03','2025-12-04 12:29:50',NULL,'2025-12-04 12:13:55','2025-12-04 12:31:03');
